INSERT INTO `MasterLairInfo` VALUES (1104,431,432,0,27,17,1,15,22,22,600,3600,300,1800,60,1103,12,110,3,7,11,'\"赂帽驴氓脕脽脌脦 录梅鲁脿赂娄 脠脡脙脛潞赂路脕 脟脧麓脵麓脧, 鲁脙脜颅 虏篓脕枚脕枚 赂酶脟脪卤卯隆娄\",\n\"驴漏卤芒掳隆 掳篓脠梅 戮卯碌貌 脕脵脌脤鲁陋 戮脣掳铆 碌茅戮卯驴脗 掳脜鲁脛?\",\n\"掳隆掳脜露贸, 鲁陋脌脟 卤脥驴漏驴卯 戮脝脌脤碌茅戮脝. 掳隆录颅 鲁冒碌茅脌禄 驴碌驴酶脟脩 戮卯碌脪 录脫脌赂路脦 脌脦碌碌脟脧掳脜露贸.\",\n\"脕露卤脻赂赂 卤芒麓脵赂庐掳脜露贸. 鲁陋脌脟 赂露路脗脌脤 掳脜脌脟 麓脵 脗梅 驴脙露煤脌赂麓脧隆娄\",\n\"鲁陋脌脟 脙忙录潞陆潞路卤 戮脝脌脤碌茅戮脝, 掳隆录颅 赂帽驴氓脜毛驴隆 麓茫脌禄 脟脟赂娄 潞赂脙忙脟脴 驴脌掳脜露贸.\",\n\"鲁脢脠帽碌茅脌脟 脙忙录潞陆脡脌禄 鲁禄掳脭 潞赂驴漏脕脰掳脜露贸.\",\n\"脗矛脗矛脗矛隆娄 鹿芦赂冒脟脧麓脵掳铆鲁陋 脟脪卤卯, 戮卯赂庐录庐麓脵掳铆鲁陋 脟脪卤卯隆娄\",\n\"脜漏脜漏?, 卤脳路隆碌碌 禄矛戮脝潞赂掳脷麓脵掳铆 鹿脽鹿枚碌脮脌禄 脛隆麓脗卤赂鲁陋.\",\n\"脕禄 麓玫 脠没脌禄 鲁禄潞赂露贸卤赂. 脌脤脕娄 陆脙脌脹脌脧 禄脫脌脦碌楼 卤脳路赂掳脭卤卯脕枚 录没脌禄 赂么戮脝 陆卢戮卯录颅戮脽隆娄\",\n\"鲁禄掳隆 潞锚赂庐脛脻露贸脛芦陆潞麓脭虏虏 鹿猫驴卯 掳脟 赂露鹿媒赂赂脌脤 戮脝麓脧露玫 掳脡 戮脣掳脭 碌脡 掳脜戮脽.\"\n','\"脟脟 录脫驴隆 脠氓赂拢麓脗 潞脪赂锚脌脟 脠没脌脤 戮冒脕篓掳隆 鲁脢脠帽赂娄 脕脳脌陆脌赂路脦 脌脦碌碌脟脪 掳脥脌脤麓脵.\",\n\"碌茅赂庐麓脌鲁脛? 鲁陋脌脟 录枚脟脧碌茅脌脤 驴茂潞脦脗垄麓脗 录脪赂庐掳隆隆娄 脌脧脕路脌脟 脌煤脕脰掳隆 麓脙 卤脳赂虏脌脷驴隆 潞脵戮卯 麓脵麓脪 掳脥脌脤麓脵.\",\n\"脌脤鹿酶驴隆麓脗 鹿掳路炉录颅掳脷麓脵赂赂, 戮冒脕篓掳隆 鲁脳鲁冒脌脟 禄矛脌潞 潞帽麓漏路脦 赂赂碌茅掳铆 脟脟麓脗 赂帽驴氓脜毛驴隆 麓茫戮脝脕脰掳脷麓脵.\"\n','\"麓漏掳隆 潞赂鲁陆 掳脥脌脤鲁脛? 鲁脳 鲁冒碌茅碌碌 脜脳脝盲脕卯脌脟 掳鲁露玫 赂禄脌脤鲁脛? 潞么戮卯赂脭脌禄 脌脷陆脛隆娄 戮冒脕篓掳拢 鲁禄 录脮脌赂路脦隆娄\",\n\"鹿矛脝脛脌脤戮卯脌脟 卤脿脕枚赂娄 脌脪脌潞 戮卯赂庐录庐脌潞 掳脥碌茅戮脝, 脌脧脕路脌脟 脌煤脕脰掳隆 麓脙 卤脳赂虏脌脷驴隆 潞脵戮卯 麓脵麓脪 掳脥脌脤麓脵.\",\n\"鲁脳 鲁冒脌脟 脟脟驴隆 脠氓赂拢麓脗 禄媒赂铆脌潞 麓漏卤赂脌脟 掳脥脌脤露玫 赂禄脌脤鲁脛? 脌潞脟媒碌碌 赂冒赂拢麓脗 戮卯赂庐录庐脌潞 鲁脿录庐碌茅隆娄\"\n','\"戮卯赂庐录庐脌潞 鲁脿录庐碌茅. 脕枚驴脕驴隆录颅鲁陋 鲁脢脠帽碌茅脌脟 鲁陋戮脿脟脭驴隆 麓芦鹿掳脌禄 脠锚赂庐掳脜露贸.\",\n\"卤貌卤貌卤貌卤貌... 掳铆脌脹 卤脳 脕陇碌碌脌脟 脠没脌赂路脦 脌脤 戮脠驴隆 鹿脽脌禄 碌茅驴漏鲁玫戮脪麓脺 赂禄脌脤鲁脛?\",\n\"脌脤脕娄 驴脥录颅 鹿脽鹿脵麓脷脌禄 脟脫脌赂赂莽 潞么戮卯潞脕戮脽 录脪驴毛戮酶脕枚 戮脢掳脷戮卯? 脜漏脜漏脜陋\"'),(1106,431,432,0,27,17,1,15,22,22,600,3600,300,1800,60,42,180,240,3,7,11,'\"赂帽驴氓脕脽脌脦 录梅鲁脿赂娄 脠脡脙脛潞赂路脕 脟脧麓脵麓脧, 鲁脙脜颅 虏篓脕枚脕枚 赂酶脟脪卤卯隆娄\",\n\"驴漏卤芒掳隆 掳篓脠梅 戮卯碌貌 脕脵脌脤鲁陋 戮脣掳铆 碌茅戮卯驴脗 掳脜鲁脛?\",\n\"掳隆掳脜露贸, 鲁陋脌脟 卤脥驴漏驴卯 戮脝脌脤碌茅戮脝. 掳隆录颅 鲁冒碌茅脌禄 驴碌驴酶脟脩 戮卯碌脪 录脫脌赂路脦 脌脦碌碌脟脧掳脜露贸.\",\n\"脕露卤脻赂赂 卤芒麓脵赂庐掳脜露贸. 鲁陋脌脟 赂露路脗脌脤 掳脜脌脟 麓脵 脗梅 驴脙露煤脌赂麓脧隆娄\",\n\"鲁陋脌脟 脙忙录潞陆潞路卤 戮脝脌脤碌茅戮脝, 掳隆录颅 赂帽驴氓脜毛驴隆 麓茫脌禄 脟脟赂娄 潞赂脙忙脟脴 驴脌掳脜露贸.\",\n\"鲁脢脠帽碌茅脌脟 脙忙录潞陆脡脌禄 鲁禄掳脭 潞赂驴漏脕脰掳脜露贸.\",\n\"脗矛脗矛脗矛隆娄 鹿芦赂冒脟脧麓脵掳铆鲁陋 脟脪卤卯, 戮卯赂庐录庐麓脵掳铆鲁陋 脟脪卤卯隆娄\",\n\"脜漏脜漏?, 卤脳路隆碌碌 禄矛戮脝潞赂掳脷麓脵掳铆 鹿脽鹿枚碌脮脌禄 脛隆麓脗卤赂鲁陋.\",\n\"脕禄 麓玫 脠没脌禄 鲁禄潞赂露贸卤赂. 脌脤脕娄 陆脙脌脹脌脧 禄脫脌脦碌楼 卤脳路赂掳脭卤卯脕枚 录没脌禄 赂么戮脝 陆卢戮卯录颅戮脽隆娄\",\n\"鲁禄掳隆 潞锚赂庐脛脻露贸脛芦陆潞麓脭虏虏 鹿猫驴卯 掳脟 赂露鹿媒赂赂脌脤 戮脝麓脧露玫 掳脡 戮脣掳脭 碌脡 掳脜戮脽.\"\n','\"脟脟 录脫驴隆 脠氓赂拢麓脗 潞脪赂锚脌脟 脠没脌脤 戮冒脕篓掳隆 鲁脢脠帽赂娄 脕脳脌陆脌赂路脦 脌脦碌碌脟脪 掳脥脌脤麓脵.\",\n\"碌茅赂庐麓脌鲁脛? 鲁陋脌脟 录枚脟脧碌茅脌脤 驴茂潞脦脗垄麓脗 录脪赂庐掳隆隆娄 脌脧脕路脌脟 脌煤脕脰掳隆 麓脙 卤脳赂虏脌脷驴隆 潞脵戮卯 麓脵麓脪 掳脥脌脤麓脵.\",\n\"脌脤鹿酶驴隆麓脗 鹿掳路炉录颅掳脷麓脵赂赂, 戮冒脕篓掳隆 鲁脳鲁冒脌脟 禄矛脌潞 潞帽麓漏路脦 赂赂碌茅掳铆 脟脟麓脗 赂帽驴氓脜毛驴隆 麓茫戮脝脕脰掳脷麓脵.\"\n','\"麓漏掳隆 潞赂鲁陆 掳脥脌脤鲁脛? 鲁脳 鲁冒碌茅碌碌 脜脳脝盲脕卯脌脟 掳鲁露玫 赂禄脌脤鲁脛? 潞么戮卯赂脭脌禄 脌脷陆脛隆娄 戮冒脕篓掳拢 鲁禄 录脮脌赂路脦隆娄\",\n\"鹿矛脝脛脌脤戮卯脌脟 卤脿脕枚赂娄 脌脪脌潞 戮卯赂庐录庐脌潞 掳脥碌茅戮脝, 脌脧脕路脌脟 脌煤脕脰掳隆 麓脙 卤脳赂虏脌脷驴隆 潞脵戮卯 麓脵麓脪 掳脥脌脤麓脵.\",\n\"鲁脳 鲁冒脌脟 脟脟驴隆 脠氓赂拢麓脗 禄媒赂铆脌潞 麓漏卤赂脌脟 掳脥脌脤露玫 赂禄脌脤鲁脛? 脌潞脟媒碌碌 赂冒赂拢麓脗 戮卯赂庐录庐脌潞 鲁脿录庐碌茅隆娄\"\n','\"戮卯赂庐录庐脌潞 鲁脿录庐碌茅. 脕枚驴脕驴隆录颅鲁陋 鲁脢脠帽碌茅脌脟 鲁陋戮脿脟脭驴隆 麓芦鹿掳脌禄 脠锚赂庐掳脜露贸.\",\n\"卤貌卤貌卤貌卤貌... 掳铆脌脹 卤脳 脕陇碌碌脌脟 脠没脌赂路脦 脌脤 戮脠驴隆 鹿脽脌禄 碌茅驴漏鲁玫戮脪麓脺 赂禄脌脤鲁脛?\",\n\"脌脤脕娄 驴脥录颅 鹿脽鹿脵麓脷脌禄 脟脫脌赂赂莽 潞么戮卯潞脕戮脽 录脪驴毛戮酶脕枚 戮脢掳脷戮卯? 脜漏脜漏脜陋\"'),(1114,433,434,1,22,14,1,15,28,21,600,3600,300,1800,60,1113,77,26,3,7,11,'\"麓毛脙录 戮卯麓脌 鲁冒脌脤鲁脛隆娄 鹿脵卤霉脌脤 鹿芦脙麓 录脪露玫陆潞路麓卤赂鲁陋.\",\n\"戮脝脕梅 碌脦路脕驴貌脌脤露玫 掳脡 掳忙脟猫脛隆 赂酶脟脩 禄媒脕茫碌茅脌脤 录没戮卯碌茅戮煤鲁陋 潞赂卤潞.\",\n\"鲁陋脌脟 录梅赂茅脌禄 鹿忙脟脴脟脩 脕脣脌脟 麓帽掳隆麓脗 脕脳脌陆潞赂麓脵 脜漏麓脵麓脗 掳脡 戮脣戮脝露贸.\",\n\"脕露卤脻赂赂 脗眉掳铆 掳脽碌冒掳脜露贸. 鲁脢脠帽碌茅脌禄 脌脤鲁禄 脟脟脌脟 脙脿脕娄 录脫脌赂路脦 脙脢麓毛脟脪 脜脳麓脧.\",\n\"脟脧脟脧脟脧脟脧隆娄 掳铆脌脹 脌脤 脕陇碌碌驴隆 戮贸卤录禄枚脌脤 潞炉脟脧麓脗 掳脜鲁脛?\",\n\"虏酶虏酶虏酶隆娄 脌脤碌没卤脻脌潞 脌脤路卤 赂脹脙禄脌脤碌茅脌脤露贸碌碌 禄媒掳脺戮脽 禄莽麓脗碌楼 脌莽鹿脤掳隆 脌脰脌禄 脜脳脕枚.\",\n\"脠陇陆脙 脕枚卤脻 禄莽脌眉脌脤 脌脰掳脜碌茅露没 \'赂赂驴毛\'脌脤露玫 麓脺戮卯 露忙脌禄 脙拢戮脝 潞赂露贸卤赂.\",\n\"驴隆陆陆露贸麓脧戮脝驴隆 录没掳脺脕酶 脌脧脕路脌脟 脠没脌潞 掳冒 鲁陋脌脟 掳脥脌脤 碌脟赂庐露贸.\",\n\"鹿煤陆谩潞脦脜脥 卤脳路赂掳脭 鲁陋掳隆露鲁戮卯脕庐录颅戮脽 鲁禄 赂冒陆脌脌潞 卤赂掳忙碌碌 赂酶脟脴潞录 掳脜 戮脝麓脩掳隆.\",\n\"鲁陋赂娄 脕禄麓玫 脠茂掳茫掳脭 脟脴脕脰脕枚 赂酶脟脧赂茅 掳茂露玫脟脩碌楼 赂禄脌脤戮脽隆娄\"\n','\"脜漏脌鹿隆娄 鲁禄掳隆 脟脧脟脢 潞脦禄贸 脕脽脌脧 露搂 麓媒潞帽麓脵麓脧隆娄 驴卯 脕脕脌潞 脕脵 戮脣戮脝露贸, 虏驴赂露.\",\n\"戮脮脌赂路脨 赂铆麓莽脌脷赂庐路脦赂赂 掳帽露贸麓脵鲁脿露贸. 麓脵脌陆驴隆 赂露脕脰脙脝脌禄 露漏 卤脳 脌脷赂庐掳隆 掳冒 鲁脳 鹿芦麓媒脌脤 碌脡 脜脳麓脧隆娄\",\n\"鲁赂脗娄脌禄 露脠露脠脠梅 卤芒戮茂脟脴碌脦赂露. 戮冒脕篓掳隆 鲁脳鲁冒 戮没碌垄脌脤驴隆 虏驴脙卢脌脤赂娄 虏莽戮卯 赂脜麓脼戮脝 脕脰戮卯戮脽 脟脪 脜脳麓脧隆娄\"\n','\"脕露鹿芦路隆卤芒 鹿猫陆脜脌脷碌茅驴隆掳脭 麓莽脟脪 脕脵脌脤戮脽. 碌脦掳铆 潞脕露贸. 麓脵脌陆 鹿酶驴拢 卤脳赂庐 陆卤脕枚 戮脢脌禄 掳脥脌脤麓脵.\",\n\"鲁禄掳脭 鹿脵脙脝麓酶 脙忙录潞脌脟 录颅戮脿脌潞 掳脜脕镁脌脤戮煤麓脺 赂禄脌脤鲁脛? 潞脪赂锚脌脟 脌掳陆脜脌脤 戮冒脕篓掳隆 鲁脢脠帽碌茅脌禄 鹿脻碌氓陆脙 赂锚脟脧