INSERT INTO `Script` VALUES (100,'卤脳路莽鹿枚','脕娄掳隆 掳隆脕枚掳铆 脌脰麓脗 脌脤 戮脟录录录颅赂庐碌茅脌潞 麓莽陆脜脌脟 卤芒潞禄脌没脌脦 脠没脌禄 脜掳驴枚脕脵 掳脥脌脭麓脧麓脵. 鹿矛脝脛脌脤戮卯碌茅掳煤 陆脦驴茂露搂 脟脢脠梅 赂鹿脌潞 碌碌驴貌脌脤 碌脟赂庐露贸掳铆 禄媒掳垄脟脮麓脧麓脵. 脟脩鹿酶 潞赂陆脙脕枚驴盲.','驴鹿. 鹿掳掳脟碌茅脌禄 潞录 录枚 脌脰脌禄卤卯驴盲?\n		 **脕娄 掳脥脌禄 脠陇陆脙 禄莽陆脟 脌脟脟芒脌脤 脌脰脌赂陆脜掳隆驴盲? 脝脠掳铆 陆脥陆脌麓脧麓脵赂赂.\n		 **录戮脜脥驴矛路脦(脝锚) 脛霉陆潞脝庐 露搂鹿庐驴隆 驴脭陆脌麓脧麓脵.\n		 **脕枚卤脻脌潞 脝炉潞掳脠梅 脟脢驴盲脟脩 掳脥脌脤 戮酶卤潞驴盲.\n		'),(101,'卤脳路莽鹿枚','录潞掳忙脙楼驴隆碌碌 戮脧脠拢掳隆 录没掳脺脕庐 脌脰麓脵麓脗 禄莽陆脟 戮脣掳铆 脌脰鲁陋? 脌脤脗脢 掳猫脜毛驴隆录颅麓脗 麓脵 戮脝麓脗 禄莽陆脟脌脤脕枚.',''),(102,'卤脳路莽鹿枚','赂冒碌莽 戮脧脠拢驴脥 潞帽鹿脨脌脤 脟庐赂掳麓脵掳铆 禄媒掳垄脟脩麓脵赂茅 卤脳掳脟 驴脌禄锚脌脤鲁脳.',''),(103,'卤脳路莽鹿枚','脟脩露搂麓脗 鲁禄掳隆 脟脴碌露脟脧脕枚 赂酶脟脧麓脗 戮脧脠拢麓脗 戮酶戮煤麓脵鲁脳. 驴盲脕貌脌脤戮脽 脛脛脟禄脜脥掳隆 麓脵 戮脣戮脝录颅 脟脧脕枚赂赂..',''),(104,'卤脳路莽鹿枚','脛脷鲁颅麓脭脌潞 鲁陋脌脟 禄媒赂铆脌脟 脌潞脌脦脌脤露贸鲁脳. 卤脳潞脨赂赂脜颅 露脵戮卯鲁颅 陆陆路鹿脌脤戮卯麓脗 潞禄 脌没脌脤 戮酶麓脵鲁脳.',''),(105,'卤脳路莽鹿枚','鲁禄掳隆 掳隆脕酶 潞铆路莽碌氓路脫脌脤 脌脷鲁脳脌脟 戮脝脌脤脜脹脌禄 麓玫 脟芒禄贸陆脙脛脩 脕脵虏篓戮脽. 脟脧脕枚赂赂 禄莽露梅脌潞 卤芒潞禄卤芒掳隆 脕脽驴盲脟脩 鹿媒脌脤脕枚. 脟脳禄贸 驴颅陆脡脠梅 录枚路脙脟脧掳脭鲁陋.',''),(106,'卤脳路莽鹿枚','脌脷鲁脳掳脭 潞脦脕路脟脩 脠没脌脤 戮卯露虏 掳脥脌脤鲁陋 脌脽 脝脛戮脟脟脴 碌脦露贸掳铆. 赂冒脌脷露玫 潞脦潞脨脌潞 戮脝脌脤脜脹脌赂路脦 潞赂脙忙脟脧麓脗 掳脥碌碌 鹿忙鹿媒 脕脽脌脟 脟脧鲁陋脕枚.',''),(110,'卤脳路莽鹿枚','脌脤路卤, 录脮麓脭脌脤 戮脝麓脧陆脙卤潞隆娄 碌路脌脤 碌脟脕枚 戮脢麓脗 脌脧脌潞 禄莽脌媒脌脤脕枚赂赂 脌脤鹿酶 掳脟脌潞 脕娄鹿媒 脠茂鹿脤路脦驴卯 脌脧脌脤脕枚. 卤脳路隆, 脌脷掳脻脌潞 掳庐脙脽掳铆 驴脌录脤掳脷脕枚驴盲?','录戮脜脥驴矛路脦 脛霉陆潞脝庐掳隆 鹿芦戮霉脌脭麓脧卤卯?\n		**录戮脜脥驴矛路脦 脛霉陆潞脝庐赂娄 驴脧路谩脟脧驴麓陆脌麓脧麓脵. 潞赂禄贸脌潞?'),(111,'卤脳路莽鹿枚','碌氓碌冒戮卯 录戮脜脥驴矛路脦赂娄 脕露脕陇脟脧陆脟 麓脡路脗脌禄 掳庐脙脽掳脭 碌脟录脤卤潞驴盲. 脙脿脟脧 碌氓赂鲁麓脧麓脵. 脌脤 录戮脜脥驴矛路脦麓脗 戮脝脕脰 脌炉驴毛脟脧脕枚赂赂 录露录录脟脩 脕娄脟掳脌脭麓脧麓脵. 戮脝脕梅 陆脜脕娄脟掳 陆脙脌氓驴隆 鲁陋驴脌脕枚碌碌 戮脢脌潞 碌没虏枚碌没虏枚脟脩 陆脜脟掳脌脭麓脧麓脵. E.V.E 脕枚碌碌潞脦驴隆录颅 脕娄脟掳脌脟 脜脳陆潞脝庐赂娄 脌脟路脷 鹿脼掳铆 脟脩脕陇脌没脌赂路脦 脕枚卤脼脟脧掳铆 脌脰麓脗 禄贸脜脗脌脭麓脧麓脵. 脌脤 脕娄脟掳脌禄 脕露脕戮脟脧陆脙路脕赂茅 戮脝脕脰 鹿脤录录脟脩 脛脺脝庐路脩驴隆碌碌 麓脡脟脴戮脽 脟脮麓脧麓脵. 戮脝陆脙麓脵陆脙脟脟 脌眉脌氓脌潞 赂脜驴矛 脠楼脌芒脟脧麓脧卤卯驴盲. 脌脤脕娄 麓莽陆脜虏虏 卤芒脠赂赂娄 碌氓赂庐掳脷陆脌麓脧麓脵. 脕娄脟掳 禄莽驴毛脌禄 脌搂脟脩 脜脳陆潞脝庐露贸掳铆 禄媒掳垄脟脧陆脙赂茅 碌脟掳脷卤潞驴盲. 麓莽陆脜脌脟 麓脡路脗驴隆 潞帽脙脽戮卯 潞录 露搂 %(MonsterName) 脌脤 掳隆脌氓 脌没脟脮脟脧卤潞驴盲. 脕娄脟脩陆脙掳拢 1陆脙掳拢 碌驴戮脠 80赂露赂庐赂娄 录潞掳酶脌没脌赂路脦 脌芒戮脝 驴脌陆脙赂茅 脜脳陆潞脝庐赂娄 脜毛掳煤脟脪 录枚 脌脰陆脌麓脧麓脵. 脜脳陆潞脝庐赂娄 脕酶脟脿脟脧陆脙掳脷陆脌麓脧卤卯?','录枚脟脿 脟脧掳脷陆脌麓脧麓脵.\n		**戮脝麓脧驴脌 麓脵脌陆卤芒脠赂赂娄 脌脤驴毛脟脧掳脷陆脌麓脧麓脵.'),(200,'陆潞赂露脌脤路脦潞帽脛隆','戮卯录颅驴脥. 脌脤鹿酶驴拢 露脟 戮卯碌冒掳隆 赂禄陆茅脌脦掳隆? 脟脩鹿酶 潞赂驴漏脕脰掳脭. 脌陆.... 录脮潞录 碌楼掳隆 赂鹿脌脻戮脝. 脌脤 脕枚掳忙